// Parse Chat Input
// Expected format (one field per line):
//   Name: Thabo Moyo
//   Omang: 123456789
//   Degree: Bachelor of Accountancy (BAcc)
//   LastKnownLocation: Gaborone

const raw = ($input.item.json.body?.chatInput || $input.item.json.chatInput || '').trim();
const lines = raw.split('\n').map(l => l.trim()).filter(Boolean);
const data = {};

for (const line of lines) {
  const match = line.match(/^([A-Za-z]+)\s*:\s*(.+)$/);
  if (match) {
    data[match[1].toLowerCase()] = match[2].trim();
  }
}

const Name = (data.name || '')
  .replace(/\/\/.*$/, '')
  .replace(/\s*Omang:.*/i, '')
  .replace(/\s*ID:.*/i, '')
  .trim();

if (!Name || Name.length < 2) {
  throw new Error(`Invalid or missing Name field. Got: "${data.name || ''}"`);
}

const Omang = (data.omang || '').replace(/\*/g, '').trim();
const Degree = (data.degree || '').trim();
const LastKnownLocation = (data.lastknownlocation || data.location || 'Botswana').trim();

return [{ json: {
  Name,
  Omang,
  Degree,
  LastKnownLocation,
  _debug: { original: data.name, cleaned: Name }
}}];

// Build OSINT Vectors — Final
const name = $input.item.json.Name || '';
const omang = $input.item.json.Omang || '';
const degree = $input.item.json.Degree || '';
const location = $input.item.json.LastKnownLocation || 'Botswana';

if (!name || name.includes('//') || name.includes('*')) {
  throw new Error(`Malformed Name: "${name}"`);
}

const degreeMap = {
  'account': 'Accountant OR Auditor',
  'audit': 'Auditor OR Internal Auditor',
  'finance': 'Finance Officer OR Financial Analyst',
  'bank': 'Banker OR Finance Officer',
  'engineer': 'Engineer',
  'civil': 'Civil Engineer OR Infrastructure',
  'electr': 'Electrical Engineer',
  'comput': 'IT Officer OR Developer OR Software Engineer',
  'ict': 'IT Officer OR Developer OR Software Engineer',
  'software': 'Software Developer OR Engineer',
  'law': 'Lawyer OR Attorney OR Legal Counsel',
  'medic': 'Doctor OR Medical Officer OR Physician',
  'nurs': 'Nurse OR Registered Nurse',
  'educat': 'Teacher OR Educator OR Lecturer',
  'teach': 'Teacher OR Educator',
  'busin': 'Business Manager OR Consultant OR Administrator',
  'manag': 'Manager OR Administrator',
  'social work': 'Social Worker OR Welfare Officer',
  'agriculture': 'Agronomist OR Agriculture Officer',
  'geology': 'Geologist',
  'mining': 'Mining Engineer OR Geologist',
  'economics': 'Economist OR Economic Analyst',
  'statistic': 'Statistician OR Data Analyst',
  'public admin': 'Public Administrator OR Government Officer',
  'human resource': 'HR Officer OR Human Resources Manager',
  'marketing': 'Marketing Officer OR Brand Manager',
  'procurement': 'Procurement Officer OR Supply Chain',
  'supply chain': 'Supply Chain Officer OR Logistics',
  'environmental': 'Environmental Officer OR Conservation'
};

let professionKeyword = '';
const lowerDegree = degree.toLowerCase();
for (const [key, value] of Object.entries(degreeMap)) {
  if (lowerDegree.includes(key)) {
    professionKeyword = value;
    break;
  }
}

if (!professionKeyword) {
  const cleanDegree = degree.replace(/\([^)]*\)/g, '').trim();
  const words = cleanDegree.split(/\s+/).filter(w =>
    !['bachelor','master','diploma','of','in','the','and','science','arts','technology'].includes(w.toLowerCase())
  );
  professionKeyword = words.slice(-2).join(' ') || degree;
}

// L1: LinkedIn profile search
const l1Query = encodeURIComponent(`"${name}" ${professionKeyword} Botswana site:linkedin.com`);

// L2a: Personal Facebook profile (public posts indexed by Google)
const l2Query = encodeURIComponent(`"${name}" site:facebook.com Botswana`);

// L2b: Botswana news, govt gazette, professional announcements
const l2bQuery = encodeURIComponent(`"${name}" site:mmegi.bw OR site:dailynews.gov.bw OR site:sundaystandard.info OR site:gazette.gov.bw OR site:jobsbotswana.info OR "appointed" OR "promoted"`);

// L2c: Corporate Facebook pages announcing staff
const l2cQuery = encodeURIComponent(`"${name}" site:facebook.com "welcome" OR "congratulates" OR "joins our team" OR "new staff" OR "promoted" Botswana`);

// L2d: LinkedIn company pages + professional directories
const l2dQuery = encodeURIComponent(`"${name}" site:linkedin.com/company OR site:zoominfo.com Botswana ${professionKeyword}`);

// L3: CIPA company registry + university staff directories
const l3Query = encodeURIComponent(`"${name}" Botswana site:cipa.co.bw OR site:ub.bw OR site:biust.ac.bw OR site:burs.org.bw OR "company director" OR "board member"`);

return [{ json: {
  Name: name,
  Omang: omang,
  Degree: degree,
  LastKnownLocation: location,
  TargetProfession: professionKeyword,
  l1Query,
  l2Query,
  l2bQuery,
  l2cQuery,
  l2dQuery,
  l3Query,
  RunTimestamp: new Date().toISOString()
}}];

// Extract L1 Snippets — proximity-enforced name guard
const vectorData = $('Build OSINT Vectors').first().json;
const targetName = (vectorData.Name || '').trim();
const nameLower = targetName.toLowerCase();
const results = $input.item.json.results || [];

const nameWords = nameLower.split(/\s+/).filter(Boolean);

const nameRegex = new RegExp(
  nameWords.map(w => '(?<![\\w])' + w.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '(?![\\w])').join('(?:\\s+\\S+){0,2}\\s+'),
  'i'
);

const useProximity = nameWords.length >= 2;
let proximityRegex = /./;
if (useProximity) {
  const fnEsc = nameWords[0].replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const snEsc = nameWords[nameWords.length - 1].replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  proximityRegex = new RegExp(
    '(?<![\\w])' + fnEsc + '(?![\\w]).{0,60}(?<![\\w])' + snEsc + '(?![\\w])' +
    '|(?<![\\w])' + snEsc + '(?![\\w]).{0,60}(?<![\\w])' + fnEsc + '(?![\\w])',
    'i'
  );
}

const matched = results.filter(r => {
  const text = [(r.title || ''), (r.content || '')].join(' ');
  return nameRegex.test(text) && (!useProximity || proximityRegex.test(text));
});

let snippet = 'NULL';
if (matched.length > 0) {
  const raw = matched
    .slice(0, 3)
    .map(r => [(r.title || ''), (r.content || '')].join(' '))
    .join(' | ')
    .substring(0, 1500);
  snippet = raw.replace(/["\\\n\r\t]/g, ' ').trim() || 'NULL';
}

return [{ json: { ...vectorData, l1_snippet: snippet, l1_name_matched_count: matched.length } }];

// Extract L2 Snippets — reads from Merge node output (all 4 L2 sources)
const prevData = $('Extract L1 Snippets').first().json;
const targetName = (prevData.Name || '').trim();
const nameLower = targetName.toLowerCase();

// Pull results from ALL items passed in by the Merge node
const allItems = $input.all();
const results = allItems.flatMap(item => item.json.results || []);

const nameWords = nameLower.split(/\s+/).filter(Boolean);

const nameRegex = new RegExp(
  nameWords.map(w => '(?<![\\w])' + w.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '(?![\\w])').join('(?:\\s+\\S+){0,2}\\s+'),
  'i'
);

const useProximity = nameWords.length >= 2;
let proximityRegex = /./;
if (useProximity) {
  const fnEsc = nameWords[0].replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const snEsc = nameWords[nameWords.length - 1].replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  proximityRegex = new RegExp(
    '(?<![\\w])' + fnEsc + '(?![\\w]).{0,60}(?<![\\w])' + snEsc + '(?![\\w])' +
    '|(?<![\\w])' + snEsc + '(?![\\w]).{0,60}(?<![\\w])' + fnEsc + '(?![\\w])',
    'i'
  );
}

const matched = results.filter(r => {
  const text = [(r.title || ''), (r.content || '')].join(' ');
  return nameRegex.test(text) && (!useProximity || proximityRegex.test(text));
});

const taggedMatches = matched.map(r => {
  let source = 'unknown';
  const url = (r.url || '').toLowerCase();
  if (url.includes('facebook.com')) source = 'facebook';
  else if (url.includes('linkedin.com')) source = 'linkedin-company';
  else if (url.includes('mmegi') || url.includes('dailynews') || url.includes('sundaystandard') || url.includes('gazette')) source = 'news/gazette';
  else if (url.includes('jobsbotswana')) source = 'jobs';
  else if (url.includes('zoominfo')) source = 'zoominfo';
  return { ...r, _source: source };
});

const facebookMatches = taggedMatches.filter(r => r._source === 'facebook').length;
const newsMatches = taggedMatches.filter(r => r._source === 'news/gazette').length;

let snippet = 'NULL';
if (taggedMatches.length > 0) {
  const raw = taggedMatches
    .slice(0, 5)
    .map(r => `[${r._source.toUpperCase()}] ` + [(r.title || ''), (r.content || '')].join(' '))
    .join(' | ')
    .substring(0, 2000);
  snippet = raw.replace(/["\\n\r\t]/g, ' ').trim() || 'NULL';
}

return [{ json: {
  ...prevData,
  l2_snippet: snippet,
  l2_name_matched_count: taggedMatches.length,
  l2_facebook_matches: facebookMatches,
  l2_news_matches: newsMatches
} }];

// Extract L3 Snippets — reads from CIPA Direct Scraper API
const prevData = $('Extract L2 Snippets').first().json;
const targetName = (prevData.Name || '').trim();
const nameLower = targetName.toLowerCase();

// CIPA API returns structured data — not SearXNG results
const cipaResponse = $input.item.json;
const cipaResults = cipaResponse.results || [];

let snippet = 'NULL';
let l3_name_matched_count = 0;

if (cipaResults.length > 0) {
  // Convert CIPA structured results to snippet format
  const raw = cipaResults.map(r => {
    const parts = [
      r.personName || '',
      r.companyLine || '',
      r.interestsLine || '',
      r.appointedLine || ''
    ].filter(Boolean).join(' | ');
    return '[CIPA_REGISTER] ' + parts;
  }).join(' || ').substring(0, 2000);

  snippet = raw.replace(/["\\\n\r\t]/g, ' ').trim() || 'NULL';

  // Count exact name matches
  l3_name_matched_count = cipaResults.filter(r => {
    const personName = (r.personName || '').toLowerCase();
    return personName.includes(nameLower.split(' ')[0]) &&
           personName.includes(nameLower.split(' ').slice(-1)[0]);
  }).length;
}

// Also store structured CIPA data for the prompt
const cipaStructured = cipaResults.map(r => ({
  name: r.personName,
  company: r.companyLine,
  registrationNo: r.registrationNo,
  interests: r.interestsLine,
  appointed: r.appointedLine
}));

return [{ json: {
  ...prevData,
  l3_snippet: snippet,
  l3_name_matched_count,
  l3_cipa_results: cipaStructured
} }];

// Format Result — Final
const rawText =
  $input.item.json.text ||
  $input.item.json.content ||
  $input.item.json.candidates?.[0]?.content?.parts?.[0]?.text ||
  '';

const d = $('Build Consolidation Prompt').first().json;

let result = {
  best_employer: 'Unknown',
  best_title: 'Unknown',
  confidence: 'NONE',
  location: d.LastKnownLocation,
  sources_matched: 0,
  best_source: 'None',
  reasoning: 'AI response could not be parsed.',
  drift_warning: false,
  action_required: true,
  name_found_in_sources: []
};

try {
  const clean = rawText.replace(/```json|```/g, '').trim();
  result = JSON.parse(clean);
} catch(e) {
  result.parse_error = e.message;
  result.raw_response = rawText.substring(0, 300);
}

// Anti-drift guard
const targetLower = (d.Name || '').trim().toLowerCase();
const foundNames = result.name_found_in_sources || [];
const validNames = foundNames.filter(n => (n || '').trim().toLowerCase() === targetLower);

if (foundNames.length > 0 && validNames.length === 0) {
  result.best_employer = 'Unknown — drift detected (AI matched wrong person)';
  result.confidence = 'NONE';
  result.drift_warning = true;
  result.drift_rejected = true;
  result.reasoning = 'AI matched names that do not equal the target ("' + foundNames.join('", "') + '"). All results rejected.';
  result.action_required = true;
}

if (d.total_matches === 0) {
  result.best_employer = 'Unknown — no exact name matches in any source';
  result.confidence = 'NONE';
  result.sources_matched = 0;
  result.reasoning = 'SearXNG returned 0 results containing the exact name "' + d.Name + '". Similar names were filtered as potential drift.';
  result.action_required = true;
}

const conf = result.confidence === 'HIGH' ? '🟢' :
             result.confidence === 'MEDIUM' ? '🟡' :
             result.confidence === 'LOW' ? '🟠' : '🔴';

const srcLine = (snippet, label, count) => {
  if (!snippet || snippet === 'NULL') return `  ❌ ${label}: No exact matches`;
  return `  ✅ ${label}: ${count} match(es) — ${snippet.substring(0, 180)}...`;
};

const l2Label = `L2 Social/News/Corporate (FB:${d.l2_facebook_matches||0} News:${d.l2_news_matches||0})`;

const output =
'━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n' +
'🔍 DTEF OSINT CONSOLIDATED TRACE\n' +
'━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n' +
'👤 TARGET\n' +
'   Name:     ' + d.Name + '\n' +
'   Omang:    ' + (d.Omang || 'N/A') + '\n' +
'   Degree:   ' + (d.Degree || 'N/A') + '\n' +
'   Location: ' + d.LastKnownLocation + '\n\n' +
conf + ' RESULT\n' +
'   Confidence:   ' + result.confidence + '\n' +
'   Employer:     ' + result.best_employer + '\n' +
'   Title:        ' + result.best_title + '\n' +
'   Location:     ' + (result.location || d.LastKnownLocation) + '\n' +
'   Best Source:  ' + (result.best_source || 'N/A') + '\n\n' +
'📊 SOURCES (' + result.sources_matched + '/3 matched)\n' +
srcLine(d.l1_snippet, 'L1 LinkedIn', d.l1_name_matched_count) + '\n' +
srcLine(d.l2_snippet, l2Label, d.l2_name_matched_count) + '\n' +
srcLine(d.l3_snippet, 'L3 CIPA/Registry', d.l3_name_matched_count) + '\n\n' +
'📝 ANALYSIS\n' + result.reasoning + '\n\n' +
(result.drift_warning ? '⚠️  DRIFT WARNING: Similar names detected and filtered.\n' : '') +
(result.action_required ? '⚠️  MANUAL VERIFICATION REQUIRED\n' : '✅ CROSS-VERIFIED — No manual action needed\n') +
'━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━';

return [{ json: result }];
